INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "フフ、全問正解よ！\nちゃんと勉強してるみたいで\n感心だわ♪", 3.18, 11300101, "vo_minigame_1012_result_1000", 1, 4, 7, 10, 10, 1, 8);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "すごいじゃない…全問正解よ！\nま、当然といや当然よね～\nだってあたしが\n教えてやってんだから♪", 3.33, 11300102, "vo_minigame_1012_result_1001", 1, 10, 8, 10, 10, 1, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "全問正解！　パチパチパチ～♪\nこの難易度はもう完璧じゃない？\n次はもっと難しい問題に挑戦よ！\nあんたならできるって！", 5.41, 11300103, "vo_minigame_1012_result_1002", 1, 10, 8, 10, 10, 1, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "へえ…難しい問題を選んだのに\n全問正解できてるじゃない！！\nちょっとあんたすごすぎだわ…！\nパーフェクトよパーフェクト！", 8.11, 11300104, "vo_minigame_1012_result_1003", 1, 10, 5, 10, 10, 2, 8);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "まる…まる…全部まる！\n難しい問題なのに全問正解よ…！\n驚いた…あんたいつの間に、\nこんなに勉強してたのよ！", 1.31, 11300105, "vo_minigame_1012_result_1004", 1, 0, 10, 10, 10, 2, 5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "ここまで完璧に正解されちゃうと\nちょっと悔しいわね…！\nけど素直に褒めてやるわ！\nえらい、えらい、えら～い！", 4.93, 11300106, "vo_minigame_1012_result_1005", 1, 0, 9, 10, 10, 2, 8);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "すごい…あんたパーフェクトよ！\nこのままいけば次の試験、\n学年一位も夢じゃないかもね！\n楽しみだわ～♪", 2.99, 11300107, "vo_minigame_1012_result_1006", 1, 4, 5, 10, 10, 3, 8);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "満点よ！　フフ、もうあんたに\n教えることはなにもないわ…！\n逆にあたしがあんたに教わりたい\nくらいよ！　…ね、先生♪", 8.37, 11300108, "vo_minigame_1012_result_1007", 1, 4, 8, 10, 10, 3, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "全・問・正・解！\n超難問揃いなのにすごいわね…！\nもしかしてだけど、\nあんたって天才！？", 5.32, 11300109, "vo_minigame_1012_result_1008", 1, 8, 7, 10, 10, 3, 5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "お、かなりいい点数ね～！\nあたしも教えがいがあるわ♪\nさ、まだまだ勉強するわよ！", 4.77, 11300110, "vo_minigame_1012_result_1009", 1, 4, 7, 9, 7, 1, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "うん、いい感じで点取れてるわ！\nこの調子で次は、\n満点を見せてほしいわね！", 2.97, 11300111, "vo_minigame_1012_result_1010", 1, 4, 8, 9, 7, 1, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "あ～惜しい！\nもうちょっとで満点じゃない！\n次はパーフェクトいけるわ！\n頑張りましょ！", 3.47, 11300112, "vo_minigame_1012_result_1011", 1, 0, 5, 9, 7, 1, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "すごい、かなりできてるわよ！\n難しい問題なのにやるじゃない！\nあとは目指せ、満点ね！", 5.32, 11300113, "vo_minigame_1012_result_1012", 1, 4, 8, 9, 7, 2, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "うん、かなりいい感じよ！\nあんたには赤点の心配なんて\nまーったくなさそうね♪\nでも勉強はやめさせないけど！", 6.49, 11300114, "vo_minigame_1012_result_1013", 1, 10, 8, 9, 7, 2, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "あーあとちょっとで\n全問正解だったのに！\n難しい問題だけどあんたなら\n次は満点狙えるわ！", 3.56, 11300115, "vo_minigame_1012_result_1014", 1, 0, 5, 9, 7, 2, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "うん、ほとんど正解よ！\nこんな難しい問題なのに、\nすごいじゃない！\nやっぱりあんた只者じゃないわ！", 5.67, 11300116, "vo_minigame_1012_result_1015", 1, 10, 8, 9, 7, 3, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "着実に成長してるって感じね？\nあんたならこの難問でも、\nいつか満点取れちゃうかも…！", 2.85, 11300117, "vo_minigame_1012_result_1016", 1, 10, 7, 9, 7, 3, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "うわー惜しいわね！\nもうちょっとで満点よ？\nま、あたしでも悩む難問だから、\nこの点数は胸を張っていいわ！", 3.88, 11300118, "vo_minigame_1012_result_1017", 1, 0, 5, 9, 7, 3, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "正解率は半分くらいか～\n悪くはないんだけど、あんたなら\nこんなもんじゃないでしょ？", 4.12, 11300119, "vo_minigame_1012_result_1018", 1, 0, 3, 6, 4, 1, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "んーはっきり言っちゃうと\n中途半端な点数ね…\nまあいいわ！こっからガンガン\n点数上げていくわよ！", 4.34, 11300120, "vo_minigame_1012_result_1019", 1, 0, 9, 6, 4, 1, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "う～ん、正直物足りない点数ね！\nあんたには期待してんだから、\nもっと頑張んなさい！", 3.15, 11300121, "vo_minigame_1012_result_1020", 1, 0, 3, 6, 4, 1, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "半分くらいの正解率か\n難しい問題だから仕方ないわね…\nでもあんたはもっとできる！\nだってあたしがついてんのよ！", 5.3, 11300122, "vo_minigame_1012_result_1021", 1, 0, 9, 6, 4, 2, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "うん、そこそこできんじゃない！\n頑張って勉強して\nさらに上を目指しましょ！", 2.55, 11300123, "vo_minigame_1012_result_1022", 1, 0, 8, 6, 4, 2, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "難問なのにこの正解率は\nよくやってる方よね！\nでもこんなところで\n満足してんじゃないわよ！？", 4.19, 11300124, "vo_minigame_1012_result_1023", 1, 0, 1, 6, 4, 2, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "難問なのに半分くらい正解\nできてんじゃない♪\nこの調子でもっと学力\n上げていきましょ！", 3.43, 11300125, "vo_minigame_1012_result_1024", 1, 0, 7, 6, 4, 3, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "よし、平均点ってとこね！\nちゃんと勉強してるみたいで\n安心したわ～♪", 0.0, 11300126, "vo_minigame_1012_result_1025", 1, 0, 1, 6, 4, 3, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "難問揃いでこの正解率は\n大したもんよ！\nま、もっといい点取りたいんなら\n勉強、付き合ったげるわ！", 3.72, 11300127, "vo_minigame_1012_result_1026", 1, 0, 8, 6, 4, 3, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "なるほど…\nこれは教えがいがあるわね\nビシバシ鍛えてやるから\n覚悟しなさい！", 3.5, 11300128, "vo_minigame_1012_result_1027", 1, 1, 3, 3, 1, 1, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "ちょっとあんた、\n全然できてないじゃない！\n…まさかこれが本気だなんて\n言わないわよね～？", 3.25, 11300129, "vo_minigame_1012_result_1028", 1, 1, 4, 3, 1, 1, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "うーん……適当に答えても\nこれくらい正解できるわよ？\nちょっと本腰入れて\n教えないとね……！", 4.62, 11300130, "vo_minigame_1012_result_1029", 1, 0, 3, 3, 1, 1, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "…ま、まあこの問題は\nあんたには難しすぎたのかもね\nちょっとずつでいいから、\nレベルアップしていきましょ！", 4.5, 11300131, "vo_minigame_1012_result_1030", 1, 0, 9, 3, 1, 2, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "んー結構ミスっちゃってるわね…\nこのまま続けるのもいいけど、\n簡単な問題からやり直すのも\nありかもよ～？", 0.01, 11300132, "vo_minigame_1012_result_1031", 1, 9, 3, 3, 1, 2, 3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "あらら、あんたにはちょっと\n難しすぎたかしら…？\nもう一回やり直しましょうか！", 0.01, 11300133, "vo_minigame_1012_result_1032", 1, 9, 9, 3, 1, 2, 9);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "うーん、残念な結果ね…\n超難問だから仕方ないけど\n無理せず簡単な問題から挑戦\nしてもいいかもよ？", 0.01, 11300134, "vo_minigame_1012_result_1033", 1, 6, 3, 3, 1, 3, 3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "正解率はかなり悪いわね…\nまあ難しい問題だもんね…！\nそのチャレンジ精神は買うわ！", 2.97, 11300135, "vo_minigame_1012_result_1034", 1, 0, 3, 3, 1, 3, 9);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "なんとか０点は免れたわね…\n難問揃いだけど、\nもっと頑張っていきましょ！", 3.1, 11300136, "vo_minigame_1012_result_1035", 1, 0, 3, 3, 1, 3, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "…あんたさ、０点なんて\n逆に取るの難しいわよ！？\nまさか狙ったわけじゃ\nないでしょーね～！？", 4.31, 11300137, "vo_minigame_1012_result_1036", 1, 1, 6, 0, 0, 1, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "０点って…\nあんたふざけてんの！？\nちゃんとやらないなら\n電撃魔法くらわせるわよ！？", 0.1, 11300138, "vo_minigame_1012_result_1037", 1, 1, 2, 0, 0, 1, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "もしかしたらあんたは\n勉強向いてないのかもね…\n…勉強だけがすべてじゃないわ\n違うとこで頑張りましょ！", 4.23, 11300139, "vo_minigame_1012_result_1038", 1, 9, 9, 0, 0, 1, 3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "怒んないから正直に言って？\n…ふざけて答えたでしょ？\nほら、正直に\n言・い・な・さ・い？", 4.38, 11300140, "vo_minigame_1012_result_1039", 1, 0, 3, 0, 0, 2, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "あんたの点数は～～…\n…はい！　０てーん！！\n…って、ふざけんなーー！！！", 3.58, 11300141, "vo_minigame_1012_result_1040", 1, 0, 8, 0, 0, 2, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (1, 3001, "０点ってどういうこと！？\nいやあんた、逆にすごいわよ！？\n目つぶってやったとしても\n１点は取れるから！", 2.02, 11300142, "vo_minigame_1012_result_1041", 1, 1, 4, 0, 0, 2, 2);
