INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "はい、よくできました！\n基礎はもう完璧ね！\n次はもっと難しい問題にも\nチャレンジしちゃいなさいよ！", 3.74, 12300101, "vo_minigame_1012_result_1045", 1, 10, 7, -1, 20, 1, 1);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "なによあんた、走り出したペンが\n止まらないって感じ？\nったくシンプルにすごいじゃない\n花丸あげるわ！", 3.85, 12300102, "vo_minigame_1012_result_1046", 1, 0, 1, -1, 20, 1, 9);
