INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "オッケー！　もう十分よ！\nこれ以上でき過ぎちゃったら、\nあたしが教える必要なくなるわ！", 2.02, 12300105, "vo_minigame_1012_result_1049", 1, 9, 5, -1, 20, 2, 3);
