INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 0.0, 12300110, "vo_minigame_1012_result_1054", 1, 0, 5, -1, 20, 1, 5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 0.0, 12300112, "vo_minigame_1012_result_1054", 1, 0, 5, -1, 20, 2, 5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 0.0, 12300114, "vo_minigame_1012_result_1054", 1, 0, 5, -1, 20, 3, 5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "おお～かなり正解できてるわね！\nこの調子でもっとすごい点\n目指しちゃうわよ！", 3.0, 12300116, "vo_minigame_1012_result_1056", 1, 10, 5, 19, 15, 1, 7);
