INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "あんた…もしかして\nあたしより点数いいかも？\nあ、あたしもあんたを見習って\n勉強しないとね…！", 3.98, 12300124, "vo_minigame_1012_result_1064", 1, 9, 5, 19, 15, 3, 9);
