INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "10問以上取れてるわね！\nえ、まだ物足りない？\nフフ、じゃあもっと上\n目指しちゃう？", 4.3, 12300136, "vo_minigame_1012_result_1072", 1, 0, 1, 14, 10, 2, 7);
