INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "やっぱおにムズだね…\nそだ、迷ったら\nヒント使うのも\nありよりのあり？", 2.51, 22300153, "vo_minigame_1012_result_2085", 2, 0, 4, 9, 5, 3, 6);
