INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "うちらまだまだ\nベンキョーちうだし…\nこれからだよねっ？\nね、ヒデサイ！", 5.28, 22300157, "vo_minigame_1012_result_2089", 2, 0, 0, 4, 1, 1, 3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "ちょっとずつ覚えれば\nおーけーっしょ！\nうちと一緒に\nベンキョーだね！", 2.89, 22300158, "vo_minigame_1012_result_2090", 2, 0, 0, 4, 1, 2, 3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "うちベンキョー苦手でも\nヒデサイとベンキョー\nするのは好き！　だから\nもっかい教えてくれる？", 5.45, 22300159, "vo_minigame_1012_result_2091", 2, 0, 0, 4, 1, 2, 7);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "覚えても、すぐ忘れるんだけど\nどしたらいい？\nあ、そーゆうとき\nフクシューする感じ？", 4.29, 22300160, "vo_minigame_1012_result_2092", 2, 3, 4, 4, 1, 2, 10);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "ムズ過ぎ！\n頭パンクするかと思った…！\nヒデサイ、うちの頭\nふぅふぅして～", 4.64, 22300161, "vo_minigame_1012_result_2093", 2, 6, 4, 4, 1, 3, 8);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！", 3.14, 22300162, "vo_minigame_1012_result_2094", 2, 0, 9, 4, 1, 3, 5);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？", 6.59, 22300163, "vo_minigame_1012_result_2095", 2, 0, 7, 4, 1, 3, 4);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！", 0.0, 22300164, "vo_minigame_1012_result_2096", 2, 0, 3, 0, 0, 1, 3);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？", 2.2, 22300165, "vo_minigame_1012_result_2097", 2, 5, 9, 0, 0, 1, 10);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？", 0.01, 22300166, "vo_minigame_1012_result_2098", 2, 6, 4, 0, 0, 1, 4);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "え、ヒデサイも０点？\nじゃあうちと一緒じゃん♪\nまあ焦んないで\nベンキョーしてこーよ！", 2.8, 22300167, "vo_minigame_1012_result_2099", 2, 3, 6, 0, 0, 2, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "むむむ～…０点…！\n覚えてもすぐ忘れちゃうし\nベンキョーってマジ大変", 3.22, 22300168, "vo_minigame_1012_result_2100", 2, 6, 9, 0, 0, 2, 4);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "０点だね…\nでも、へーきへーき\nリベンジしたら、結果オーライ！", 2.1, 22300169, "vo_minigame_1012_result_2101", 2, 11, 4, 0, 0, 2, 0);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "おやつ休憩して\nリベンジしよっ！\n甘いの食べたら、イケるっしょ！", 2.74, 22300170, "vo_minigame_1012_result_2102", 2, 3, 0, 0, 0, 3, 2);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "ヒデサイでも\nおにムズな感じ？\nじゃあ、このテスト\n誰も解けなくない？", 3.0, 22300171, "vo_minigame_1012_result_2103", 2, 9, 6, 0, 0, 3, 9);
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES (2, 3001, "…あれ？\n０が〇に見えてきた！\nきゃはっ、ちょっち\nやる気出てきたかも！", 4.37, 22300172, "vo_minigame_1012_result_2104", 2, 0, 10, 0, 0, 3, 2);
